<?php
/**
 * Database Setup and Installation Script
 * Monastery Healthcare System v2.0
 */

// Include database configuration
require_once __DIR__ . '/../config/database.php';
require_once __DIR__ . '/../app/Database.php';

class DatabaseSetup {
    private $output = [];
    
    public function install() {
        $this->output[] = "🏥 Monastery Healthcare System Database Setup";
        $this->output[] = "================================================";
        
        try {
            // Step 1: Create database
            $this->output[] = "Step 1: Creating database...";
            if (Database::createDatabaseIfNotExists()) {
                $this->output[] = "✅ Database '" . DB_NAME . "' created successfully";
            } else {
                throw new Exception("Failed to create database");
            }
            
            // Step 2: Connect to database
            $this->output[] = "Step 2: Connecting to database...";
            $db = Database::getInstance();
            if ($db->isConnected()) {
                $this->output[] = "✅ Database connection successful";
            } else {
                throw new Exception("Failed to connect to database");
            }
            
            // Step 3: Execute SQL schema
            $this->output[] = "Step 3: Creating database tables...";
            $sqlFile = __DIR__ . '/../config/monastery_database.sql';
            
            if (file_exists($sqlFile)) {
                $db->executeSQLFile($sqlFile);
                $this->output[] = "✅ Database schema created successfully";
            } else {
                throw new Exception("SQL file not found: $sqlFile");
            }
            
            // Step 4: Insert sample data
            $this->output[] = "Step 4: Inserting sample data...";
            $this->insertSampleData($db);
            $this->output[] = "✅ Sample data inserted successfully";
            
            // Step 5: Verify installation
            $this->output[] = "Step 5: Verifying installation...";
            $this->verifyInstallation($db);
            $this->output[] = "✅ Installation verified successfully";
            
            $this->output[] = "";
            $this->output[] = "🎉 Installation completed successfully!";
            $this->output[] = "";
            $this->output[] = "Default login credentials:";
            $this->output[] = "📧 Email: admin@monastery.lk";
            $this->output[] = "🔑 Password: admin123";
            $this->output[] = "";
            $this->output[] = "Additional test users:";
            $this->output[] = "👨‍⚕️ Doctor: doctor@monastery.lk / doctor123";
            $this->output[] = "🧘 Monk: monk@monastery.lk / monk123";
            $this->output[] = "💝 Donator: donor@monastery.lk / donor123";
            
        } catch (Exception $e) {
            $this->output[] = "❌ Installation failed: " . $e->getMessage();
            throw $e;
        }
        
        return $this->output;
    }
    
    private function insertSampleData($db) {\n        // Insert additional users with proper password hashing\n        $password = password_hash('admin123', PASSWORD_BCRYPT);\n        $doctorPassword = password_hash('doctor123', PASSWORD_BCRYPT);\n        $monkPassword = password_hash('monk123', PASSWORD_BCRYPT);\n        $donorPassword = password_hash('donor123', PASSWORD_BCRYPT);\n        \n        // Check if admin already exists\n        $adminExists = $db->fetch(\"SELECT id FROM users WHERE email = 'admin@monastery.lk'\");\n        \n        if (!$adminExists) {\n            // Insert admin user\n            $adminId = $db->insert('users', [\n                'email' => 'admin@monastery.lk',\n                'password_hash' => $password,\n                'role' => 'admin',\n                'full_name' => 'System Administrator',\n                'phone' => '+94701234567',\n                'status' => 'active'\n            ]);\n        }\n        \n        // Insert sample doctor\n        $doctorId = $db->insert('users', [\n            'email' => 'doctor@monastery.lk',\n            'password_hash' => $doctorPassword,\n            'role' => 'doctor',\n            'full_name' => 'Dr. Samantha Silva',\n            'phone' => '+94712345678',\n            'status' => 'active'\n        ]);\n        \n        $db->insert('doctors', [\n            'user_id' => $doctorId,\n            'doctor_id' => 'DOC001',\n            'specialization' => 'General Medicine',\n            'qualifications' => 'MBBS, MD',\n            'experience_years' => 10,\n            'license_number' => 'SL-MED-12345',\n            'available_days' => 'monday,tuesday,wednesday,thursday,friday',\n            'availability_start' => '09:00:00',\n            'availability_end' => '17:00:00',\n            'status' => 'active'\n        ]);\n        \n        // Insert sample monk\n        $monkId = $db->insert('users', [\n            'email' => 'monk@monastery.lk',\n            'password_hash' => $monkPassword,\n            'role' => 'monk',\n            'full_name' => 'Venerable Thero',\n            'phone' => '+94723456789',\n            'status' => 'active'\n        ]);\n        \n        $db->insert('monks', [\n            'user_id' => $monkId,\n            'monk_id' => 'MONK001',\n            'ordained_date' => '2015-06-15',\n            'age' => 45,\n            'emergency_contact' => 'Sister Clara',\n            'emergency_phone' => '+94734567890',\n            'blood_group' => 'O+',\n            'medical_conditions' => 'None',\n            'room_id' => 1,\n            'status' => 'active'\n        ]);\n        \n        // Insert sample donator\n        $donatorId = $db->insert('users', [\n            'email' => 'donor@monastery.lk',\n            'password_hash' => $donorPassword,\n            'role' => 'donator',\n            'full_name' => 'John Fernando',\n            'phone' => '+94745678901',\n            'status' => 'active'\n        ]);\n        \n        $db->insert('donators', [\n            'user_id' => $donatorId,\n            'donator_id' => 'DON001',\n            'address' => '123 Temple Road, Colombo 7',\n            'city' => 'Colombo',\n            'postal_code' => '00700',\n            'country' => 'Sri Lanka',\n            'total_donated' => 0.00,\n            'donation_count' => 0,\n            'preferred_categories' => 'food,medical'\n        ]);\n        \n        // Insert sample donations\n        $db->insert('donations', [\n            'donation_id' => 'DON-' . date('Y') . '-001',\n            'donator_id' => 1, // Assuming first donator\n            'category_id' => 1, // Food category\n            'amount' => 25000.00,\n            'donation_method' => 'bank_transfer',\n            'transaction_reference' => 'TXN123456789',\n            'status' => 'completed',\n            'donation_date' => date('Y-m-d'),\n            'receipt_number' => 'REC-001',\n            'notes' => 'Monthly food donation'\n        ]);\n        \n        $db->insert('donations', [\n            'donation_id' => 'DON-' . date('Y') . '-002',\n            'donator_id' => 1,\n            'category_id' => 2, // Medical category\n            'amount' => 15000.00,\n            'donation_method' => 'online',\n            'transaction_reference' => 'TXN123456790',\n            'status' => 'completed',\n            'donation_date' => date('Y-m-d', strtotime('-5 days')),\n            'receipt_number' => 'REC-002',\n            'notes' => 'Medical supplies donation'\n        ]);\n        \n        // Update current amounts in donation categories\n        $db->query(\"UPDATE donation_categories SET current_amount = (\n            SELECT COALESCE(SUM(d.amount), 0)\n            FROM donations d\n            WHERE d.category_id = donation_categories.id AND d.status = 'completed'\n        )\");\n        \n        // Insert sample medical record\n        $db->insert('medical_records', [\n            'record_id' => 'MED-' . date('Y') . '-001',\n            'monk_id' => 1,\n            'doctor_id' => 1,\n            'visit_date' => date('Y-m-d'),\n            'chief_complaint' => 'Regular health checkup',\n            'diagnosis' => 'General health is good. No major concerns.',\n            'prescription' => 'Multivitamin supplements daily',\n            'treatment_notes' => 'Advised to maintain regular exercise and meditation',\n            'vital_signs' => json_encode([\n                'blood_pressure' => '120/80',\n                'temperature' => '98.6',\n                'pulse' => '72',\n                'weight' => '65'\n            ]),\n            'status' => 'completed'\n        ]);\n        \n        // Insert sample expense\n        $db->insert('expenses', [\n            'expense_id' => 'EXP-' . date('Y') . '-001',\n            'category_id' => 1, // Food category\n            'amount' => 15000.00,\n            'description' => 'Monthly groceries and cooking supplies',\n            'expense_date' => date('Y-m-d'),\n            'vendor_name' => 'City Grocery Store',\n            'payment_method' => 'cash',\n            'status' => 'approved',\n            'approved_by' => $adminExists ? $adminExists['id'] : 1,\n            'approved_at' => date('Y-m-d H:i:s'),\n            'created_by' => $adminExists ? $adminExists['id'] : 1\n        ]);\n    }\n    \n    private function verifyInstallation($db) {\n        // Check if all tables exist\n        $tables = [\n            'users', 'monks', 'doctors', 'donators', 'rooms',\n            'donation_categories', 'donations', 'expenses',\n            'medical_records', 'appointments', 'audit_logs'\n        ];\n        \n        foreach ($tables as $table) {\n            $result = $db->fetch(\"SHOW TABLES LIKE '{$table}'\");\n            if (!$result) {\n                throw new Exception(\"Table '{$table}' not found\");\n            }\n        }\n        \n        // Check if admin user exists\n        $admin = $db->fetch(\"SELECT * FROM users WHERE role = 'admin' LIMIT 1\");\n        if (!$admin) {\n            throw new Exception(\"Admin user not found\");\n        }\n        \n        // Check if categories exist\n        $categoryCount = $db->count('donation_categories');\n        if ($categoryCount < 6) {\n            throw new Exception(\"Donation categories not properly created\");\n        }\n    }\n    \n    public function checkRequirements() {\n        $requirements = [];\n        \n        // PHP version\n        $requirements['PHP Version'] = [\n            'required' => '7.4+',\n            'current' => PHP_VERSION,\n            'status' => version_compare(PHP_VERSION, '7.4.0', '>=') ? 'OK' : 'FAIL'\n        ];\n        \n        // PDO MySQL extension\n        $requirements['PDO MySQL'] = [\n            'required' => 'Enabled',\n            'current' => extension_loaded('pdo_mysql') ? 'Enabled' : 'Disabled',\n            'status' => extension_loaded('pdo_mysql') ? 'OK' : 'FAIL'\n        ];\n        \n        // MySQLi extension\n        $requirements['MySQLi'] = [\n            'required' => 'Enabled',\n            'current' => extension_loaded('mysqli') ? 'Enabled' : 'Disabled',\n            'status' => extension_loaded('mysqli') ? 'OK' : 'WARN'\n        ];\n        \n        // JSON extension\n        $requirements['JSON'] = [\n            'required' => 'Enabled',\n            'current' => extension_loaded('json') ? 'Enabled' : 'Disabled',\n            'status' => extension_loaded('json') ? 'OK' : 'FAIL'\n        ];\n        \n        // Session support\n        $requirements['Session Support'] = [\n            'required' => 'Enabled',\n            'current' => function_exists('session_start') ? 'Enabled' : 'Disabled',\n            'status' => function_exists('session_start') ? 'OK' : 'FAIL'\n        ];\n        \n        // File permissions\n        $writableDirectories = ['uploads', 'logs'];\n        foreach ($writableDirectories as $dir) {\n            $path = __DIR__ . '/../' . $dir;\n            if (!is_dir($path)) {\n                mkdir($path, 0755, true);\n            }\n            \n            $requirements[\"Write Access ({$dir})\"] = [\n                'required' => 'Writable',\n                'current' => is_writable($path) ? 'Writable' : 'Not Writable',\n                'status' => is_writable($path) ? 'OK' : 'FAIL'\n            ];\n        }\n        \n        return $requirements;\n    }\n}\n\n// Handle installation request\nif ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['install'])) {\n    try {\n        $installer = new DatabaseSetup();\n        $output = $installer->install();\n        $success = true;\n    } catch (Exception $e) {\n        $output = ['❌ Installation failed: ' . $e->getMessage()];\n        $success = false;\n    }\n}\n\n// Check requirements\n$installer = new DatabaseSetup();\n$requirements = $installer->checkRequirements();\n?>\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <title>Database Setup - Monastery Healthcare System</title>\n    <style>\n        * { margin: 0; padding: 0; box-sizing: border-box; }\n        body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Arial, sans-serif; background: #f8fafc; padding: 2rem; }\n        .container { max-width: 800px; margin: 0 auto; }\n        .card { background: white; padding: 2rem; border-radius: 12px; box-shadow: 0 4px 8px rgba(0,0,0,0.1); margin-bottom: 2rem; }\n        h1 { color: #2563eb; margin-bottom: 2rem; text-align: center; }\n        h2 { color: #1f2937; margin-bottom: 1rem; }\n        .requirements { margin-bottom: 2rem; }\n        .requirement { display: flex; justify-content: space-between; align-items: center; padding: 0.5rem 0; border-bottom: 1px solid #e5e7eb; }\n        .requirement:last-child { border-bottom: none; }\n        .status-ok { color: #059669; font-weight: bold; }\n        .status-warn { color: #d97706; font-weight: bold; }\n        .status-fail { color: #dc2626; font-weight: bold; }\n        .install-btn { width: 100%; padding: 1rem; background: #2563eb; color: white; border: none; border-radius: 8px; font-size: 1rem; font-weight: 500; cursor: pointer; transition: background 0.2s; }\n        .install-btn:hover { background: #1d4ed8; }\n        .install-btn:disabled { background: #9ca3af; cursor: not-allowed; }\n        .output { background: #f9fafb; padding: 1rem; border-radius: 6px; font-family: monospace; white-space: pre-line; max-height: 400px; overflow-y: auto; }\n        .success { background: #f0fdf4; border-left: 4px solid #22c55e; }\n        .error { background: #fef2f2; border-left: 4px solid #ef4444; }\n        .back-link { text-align: center; margin-top: 2rem; }\n        .back-link a { color: #2563eb; text-decoration: none; }\n    </style>\n</head>\n<body>\n    <div class=\"container\">\n        <div class=\"card\">\n            <h1>🏥 Monastery Healthcare System</h1>\n            <h2>Database Setup & Installation</h2>\n            \n            <?php if (isset($output)): ?>\n                <div class=\"output <?= $success ? 'success' : 'error' ?>\">\n                    <?= implode(\"\\n\", $output) ?>\n                </div>\n                \n                <?php if ($success): ?>\n                    <div class=\"back-link\">\n                        <a href=\"../\">🚀 Go to Application</a>\n                    </div>\n                <?php endif; ?>\n                \n            <?php else: ?>\n                <h3>System Requirements</h3>\n                <div class=\"requirements\">\n                    <?php foreach ($requirements as $name => $req): ?>\n                        <div class=\"requirement\">\n                            <span><strong><?= $name ?>:</strong> <?= $req['current'] ?></span>\n                            <span class=\"status-<?= strtolower($req['status']) ?>\"><?= $req['status'] ?></span>\n                        </div>\n                    <?php endforeach; ?>\n                </div>\n                \n                <?php\n                $canInstall = true;\n                foreach ($requirements as $req) {\n                    if ($req['status'] === 'FAIL') {\n                        $canInstall = false;\n                        break;\n                    }\n                }\n                ?>\n                \n                <form method=\"POST\">\n                    <button type=\"submit\" name=\"install\" class=\"install-btn\" \n                            <?= $canInstall ? '' : 'disabled' ?>>\n                        <?= $canInstall ? '🚀 Install Database' : '❌ Fix Requirements First' ?>\n                    </button>\n                </form>\n                \n                <?php if (!$canInstall): ?>\n                    <p style=\"margin-top: 1rem; color: #dc2626; text-align: center;\">\n                        Please fix the failed requirements before installing.\n                    </p>\n                <?php endif; ?>\n            <?php endif; ?>\n        </div>\n    </div>\n</body>\n</html>